import{_ as t,o as r,c as o,aa as a}from"./chunks/framework.vXJbu8_U.js";const f=JSON.parse('{"title":"Migration","description":"","frontmatter":{},"headers":[],"relativePath":"guide/migration.md","filePath":"guide/migration.md","lastUpdated":1781017578000}'),d={name:"guide/migration.md"};function c(n,e,i,s,l,h){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="migration" tabindex="-1">Migration <a class="header-anchor" href="#migration" aria-label="Permalink to &quot;Migration&quot;">​</a></h1><h2 id="from-farfetched" tabindex="-1">From farfetched <a class="header-anchor" href="#from-farfetched" aria-label="Permalink to &quot;From farfetched&quot;">​</a></h2><p>The mental model is close, so most code maps directly. The main shift: <strong>bring your own effect</strong>, and inline options are available alongside operators.</p><table tabindex="0"><thead><tr><th>farfetched</th><th>effector-refetch</th></tr></thead><tbody><tr><td><code>createQuery({ handler })</code></td><td><code>createQuery({ effect })</code> (or <code>{ handler }</code>)</td></tr><tr><td><code>createJsonQuery({ ... })</code></td><td><code>createJsonQuery({ request, response })</code></td></tr><tr><td><code>retry(query, { times, delay })</code></td><td><code>retry(query, …)</code> <strong>or</strong> inline <code>createQuery({ retry })</code></td></tr><tr><td><code>cache(query, { ... })</code></td><td><code>cache(query, …)</code> <strong>or</strong> inline <code>createQuery({ cache })</code></td></tr><tr><td><code>concurrency(query, { strategy })</code></td><td><code>concurrency(query, …)</code> <strong>or</strong> inline <code>createQuery({ concurrency })</code></td></tr><tr><td><code>connectQuery({ source, fn, target })</code></td><td>identical</td></tr><tr><td><code>createMutation</code></td><td><code>createMutation</code> (+ <code>mutate</code> alias)</td></tr><tr><td>contracts</td><td><code>zodContract</code> / <code>standardSchemaContract</code> / <code>createContract</code></td></tr><tr><td><code>$data / $error / $status / $pending</code></td><td>same names</td></tr></tbody></table><p>Notable differences:</p><ul><li>The query wraps a <strong>real effect</strong> (<code>query.__.effect</code>), visible in devtools.</li><li>Cancellation is real for <code>createRequestFx</code> effects (AbortSignal), not just discard.</li><li>Sourced config is available inline (a <code>Store</code> for <code>concurrency</code> / <code>retry.times</code> / <code>cache.staleAfter</code> / <code>enabled</code>).</li><li><code>useUnit(query)</code> works directly in React and Vue via <code>@@unitShape</code>.</li></ul><p>What&#39;s not here yet (vs farfetched): a Solid binding, the full sourced surface on every field, and some JSON-contract conveniences. See the <a href="https://github.com/Olovyannikov/effector-query/blob/main/ROADMAP.md" target="_blank" rel="noreferrer">roadmap</a>.</p><h2 id="within-0-x" tabindex="-1">Within 0.x <a class="header-anchor" href="#within-0-x" aria-label="Permalink to &quot;Within 0.x&quot;">​</a></h2><p>Pre-1.0 the API may still change between minor versions; breaking changes are called out in the changelog. Notable so far:</p><ul><li>Web-storage cache adapters take an <strong>options object</strong> now: <code>localStorageCache({ version, maxAge })</code> (previously a prefix string).</li></ul>',10)])])}const g=t(d,[["render",c]]);export{f as __pageData,g as default};
